update pm_project set projectType = #{projectType,jdbcType=VARCHAR}, projectCode = #{projectCode,jdbcType=VARCHAR}, projectName = #{projectName,jdbcType=VARCHAR}, projectState = #{projectState,jdbcType=VARCHAR}, isback = #{isback,jdbcType=VARCHAR}, column001 = #{column001,jdbcType=VARCHAR}, column002 = #{column002,jdbcType=VARCHAR}, column003 = #{column003,jdbcType=VARCHAR}, column004 = #{column004,jdbcType=VARCHAR}, column005 = #{column005,jdbcType=VARCHAR}, column006 = #{column006,jdbcType=VARCHAR}, column007 = #{column007,jdbcType=VARCHAR}, column008 = #{column008,jdbcType=VARCHAR}, column009 = #{column009,jdbcType=TIMESTAMP}, column010 = #{column010,jdbcType=VARCHAR}, column011 = #{column011,jdbcType=VARCHAR}, column012 = #{column012,jdbcType=VARCHAR}, columno12_readonly = #{columno12_readonly,jdbcType=INTEGER}, column013 = #{column013,jdbcType=VARCHAR}, customerProjectName = #{customerProjectName,jdbcType=VARCHAR}, salesType = #{salesType,jdbcType=VARCHAR}, compId = #{compId,jdbcType=INTEGER}, createTime = #{createTime,jdbcType=TIMESTAMP}, createBy = #{createBy,jdbcType=VARCHAR}, updateTime = #{updateTime,jdbcType=TIMESTAMP}, updateBy = #{updateBy,jdbcType=VARCHAR}, effectiveFrom = #{effectiveFrom,jdbcType=TIMESTAMP}, effectiveTo = #{effectiveTo,jdbcType=TIMESTAMP}, disabled = #{disabled,jdbcType=BIT}, projectStartTime = #{projectStartTime,jdbcType=TIMESTAMP}, projectRefreshTime = #{projectRefreshTime,jdbcType=TIMESTAMP}, projectCloseTime = #{projectCloseTime,jdbcType=TIMESTAMP},
customInfo = JSON_MERGE_PATCH(IFNULL(customInfo, "{}"), #{customInfo,jdbcType=JSON}),
customConfig = JSON_MERGE_PATCH(IFNULL(customConfig, "{}"), #{customConfig,jdbcType=JSON}), column014 = #{column014,jdbcType=LONGVARCHAR} where projectId = #{projectId,jdbcType=INTEGER}

if.if:
(ph.projectName like concat("%", #{model.projectName, jdbcType=VARCHAR}, "%") OR
 ph.customInfo -> '$.projectAlias' like concat("%", #{model.projectName, jdbcType=VARCHAR}, "%")
) AND

mapper.select:
select t1.basicDataName as column012, pppfs.projectType, pppfs.objId as relateId, pppfs.channelName as agentChannel,
ifnull(podfs.contractNo, pppfs.projectCode) as contractNo, case when pppfs.projectCode is null then podfs.contractNo else pppfs.projectCode end as projectCode, ifnull(if(podfs.salesType = '01' and #{projectType} = '10', podfs.projectName, pppfs.projectName), podfs.projectName) as projectName, podfs.orderCreateTime column009, podfs.customerCode column002, podfs.customerName column003, pppfs.salesManCode salesManCode, pppfs.salesManName salesManName, pppfs.marketCode marketCode, pppfs.marketName column004, pppfs.systemId systemId, pppfs.systemName column005, pppfs.expendId expendId, pppfs.expendName column006, pppfs.industryId, pppfs.industryName column007, pppfs.officeCode column001, fd.departmentName officeName, ppm.memberCode serviceManagerCode, ppm.memberName serviceManagerCodeforjson, pph.column008 column008, pph.column010 column010, pph.column011 column011, pph.column012 column012, IFNULL(t1.basicDataName, -1) as column012Readonly, pph.column013 column013, ifnull(podfs.compCode, pppfs.corporationCode) as compCode, ifnull(c.id, c1.id) as compId, ifnull(podfs.salesType, pppfs.projectType) as salesType, pppfs.projectMoney as smsProjectAmount, pppfs.projectCode as smsProjectCode, pppfs.submitTime as smsSubmitTime, pppfs.orderExecNumber as smsOrderExecNumber
,concat( '{', concat('"customerPerson":"', ifnull(pppfs.receiveMen, ""), '"'), concat(',"customerTel":"', ifnull(pppfs.reveiveContactWay,""), '"'), concat(',"customerAddress":"', ifnull(pppfs.receiveAddress,""), '"'), concat(',"afxxReason":"', ifnull( pppfs.lendCause, ""), '"'), concat(',"requireInDate":"', ifnull(pppfs.requireInDate, ""), '"'), concat(',"pspm":"', ifnull( pppfs.pspm, ""), '"'), concat(',"pspmName":"', ifnull( pppfs.pspmName, ""), '"'), concat(',"salesMenTel":"', ifnull( pppfs.salesMenTel, ""), '"'), concat(',"decPath":"', ifnull( pppfs.decPath, ""), '"') , '}') as customInfo
from pm_project_property_af_from_sms pppfs left join pm_order_data_from_sap podfs on podfs.orderExecNumber = pppfs.orderExecNumber left join pm_project pph on podfs.contractNo = pph.projectCode and pppfs.projectType = pph.projectType left join fnd_department fd on fd.departmentNum = pppfs.officeCode left join pm_project_member ppm on pph.projectId = ppm.projectId and ppm.effectiveFrom <= now() and (ppm.effectiveTo > now() or ppm.effectiveTo is null) left join fnd_basic_data t1 on pppfs.serviceTypeName = t1.basicDataId and t1.dataTypeCode = 21 and t1.effectiveFrom <= now() and ( t1.effectiveTo > now() or t1.effectiveTo is null ) left join fnd_company c on c.code = podfs.compCode left join fnd_company c1 on c1.code = pppfs.corporationCode
where pppfs.projectType = #{projectType}
and pppfs.projectCode = #{contractNo}
and podfs.contractNo = #{contractNo}
order by podfs.id desc limit 1

select count(pm.id) > 0 and count(ui.id) > 0 as `all`, count(pm.id) > 0 as edit, count(ui.id) > 0 view, group_concat(distinct ph.projectType) as projectTypes, max(ph.projectState) as maxState, group_concat(distinct pm.memberRole) memberRoles, #{permissionTypes} as permissionTypes from pm_project ph left join pm_project_member pm on ph.projectId = pm.projectId and pm.effectiveFrom <= now() and ( pm.effectiveTo > now() or pm.effectiveTo is null ) and pm.memberCode = #{user.userName}
left join t_user_info ui on ui.`id` = #{user.userInfoId}
AND FIND_IN_SET(ph.`column001`, #{model.officeCodes}) and find_in_set(ph.`column001`, ui.`custom5`)
and find_in_set(ph.projectType, ui.custom4) where ( pm.memberCode = #{user.userName} or ui.id = #{user.userInfoId} )
AND ph.projectId = #{model.projectId}
AND FIND_IN_SET(ph.projectId, #{model.projectIds})
AND FIND_IN_SET(ph.`projectType`, #{model.projectTypes})
AND FIND_IN_SET(ph.`column001`, #{model.officeCodes})
